    doc_len_le[2] = (unsigned char)((doc_len >> 16) & 0xFF);
    doc_len_le[3] = (unsigned char)((doc_len >> 24) & 0xFF);
    fwrite(doc_len_le, 1, 4, f);

    /* Write XML document */
    fwrite(xml_doc, 1, doc_len, f);

    fclose(f);
    return 0;
}
```

